export function script(input) {
  const normalizeEndpoint = (value) => {
    const text = String(value || '').trim();
    try {
      const parsed = new URL(text);
      if (!['http:', 'https:'].includes(parsed.protocol)) return 'https://invalid.invalid/graphql';
      parsed.hash = '';
      return parsed.toString();
    } catch {
      return 'https://invalid.invalid/graphql';
    }
  };
  const endpoint = normalizeEndpoint(input.graphqlEndpoint);
  const suppliedSampleQuery = String(input.sampleQuery || '').trim();
  const sampleQuery = suppliedSampleQuery || '{ __typename }';
  const introspectionQuery = 'query SentrisIntrospectionProbe { __schema { queryType { name } mutationType { name } subscriptionType { name } directives { name } types { kind name fields { name args { name } } } } }';
  return {
    endpoint,
    introspectionBody: JSON.stringify({ query: introspectionQuery }),
    sampleQueryBody: JSON.stringify({ query: sampleQuery }),
    jsonHeaders: {
      Accept: 'application/json',
      'Content-Type': 'application/json',
      'User-Agent': 'SentrisFlow-GraphQL-Audit/1.0'
    },
    htmlHeaders: {
      Accept: 'text/html,application/xhtml+xml,application/json;q=0.9,*/*;q=0.8',
      'User-Agent': 'SentrisFlow-GraphQL-Audit/1.0'
    }
  };
}

export function script(input) {
  const statusOk = (status) => Number(status || 0) >= 200 && Number(status || 0) < 300;
  const asArray = (value) => Array.isArray(value) ? value : [];
  const endpoint = String(input.endpoint || '').trim();
  const schema = input.introspectionData?.data?.__schema;
  const introspectionErrors = asArray(input.introspectionData?.errors);
  const sampleErrors = asArray(input.sampleQueryData?.errors);
  const hasAuthError = [...introspectionErrors, ...sampleErrors].some((error) => /unauth|forbidden|permission|login|token|credential/i.test(String(error?.message || error || '')));
  const types = asArray(schema?.types);
  const introspectionEnabled = statusOk(input.introspectionStatus) && schema && types.length > 0;
  const mutationTypeName = schema?.mutationType?.name || 'Mutation';
  const mutationType = types.find((type) => type?.name === mutationTypeName);
  const mutationFields = asArray(mutationType?.fields);
  const riskyMutationPattern = /delete|remove|update|create|set|reset|login|register|token|password|admin|role|invite|upload|payment|billing/i;
  const sensitivePattern = /password|passwd|token|secret|api[-_]?key|session|cookie|email|phone|address|role|admin|payment|billing|ssn|mfa|totp|oauth/i;
  const riskyMutations = mutationFields.filter((field) => riskyMutationPattern.test(String(field?.name || ''))).map((field) => ({ name: field.name, args: asArray(field.args).map((arg) => arg?.name).filter(Boolean) }));
  const sensitiveSchemaSignals = [];
  for (const type of types) {
    const typeName = String(type?.name || '');
    if (!typeName || typeName.startsWith('__')) continue;
    if (sensitivePattern.test(typeName)) sensitiveSchemaSignals.push({ type: typeName, field: null, reason: 'sensitive type name' });
    for (const field of asArray(type?.fields)) {
      const fieldName = String(field?.name || '');
      if (sensitivePattern.test(fieldName)) {
        sensitiveSchemaSignals.push({ type: typeName, field: fieldName, reason: 'sensitive field name' });
      }
    }
  }
  const landingRawBody = String(input.landingRawBody || '');
  const graphqlIdeExposed = statusOk(input.landingStatus) && /graphiql|graphql playground|apollo sandbox|graphql voyager|__schema|introspection/i.test(landingRawBody);
  const sampleQuerySucceeded = statusOk(input.sampleQueryStatus) && Boolean(input.sampleQueryData?.data) && sampleErrors.length === 0;
  const findings = [];
  if (introspectionEnabled) {
    let priorityScore = 70;
    const priorityReasons = ['GraphQL introspection succeeded without authentication'];
    if (sampleQuerySucceeded) { priorityScore += 10; priorityReasons.push('benign unauthenticated sample query succeeded'); }
    if (riskyMutations.length > 0) { priorityScore += Math.min(20, riskyMutations.length * 10); priorityReasons.push('schema exposes risky mutation names'); }
    if (sensitiveSchemaSignals.length > 0) { priorityScore += Math.min(15, sensitiveSchemaSignals.length * 3); priorityReasons.push('schema exposes sensitive-looking types or fields'); }
    findings.push({
      ruleId: 'unauthenticated-graphql-introspection',
      title: 'Unauthenticated GraphQL introspection exposes schema details',
      severity: priorityScore >= 90 ? 'critical' : 'high',
      priorityScore,
      priorityReasons,
      evidence: {
        endpoint,
        status: input.introspectionStatus,
        queryType: schema?.queryType?.name || null,
        mutationType: schema?.mutationType?.name || null,
        subscriptionType: schema?.subscriptionType?.name || null,
        typeCount: types.length,
        riskyMutations: riskyMutations.slice(0, 20),
        sensitiveSchemaSignals: sensitiveSchemaSignals.slice(0, 30)
      },
      nextSteps: ['Verify whether introspection is intended in production', 'Review exposed mutation authorization with an authenticated and unauthenticated browser model', 'Use schema field names only as leads; do not submit sensitive data or perform destructive mutations']
    });
  }
  if (graphqlIdeExposed) {
    findings.push({
      ruleId: 'graphql-ide-exposed',
      title: 'GraphQL IDE or explorer appears exposed at the endpoint',
      severity: introspectionEnabled ? 'medium' : 'low',
      priorityScore: introspectionEnabled ? 55 : 30,
      priorityReasons: ['endpoint landing page contains GraphQL IDE/explorer markers'],
      evidence: { endpoint, landingStatus: input.landingStatus, contentType: input.landingHeaders?.['content-type'] || input.landingHeaders?.['Content-Type'] || null },
      nextSteps: ['Confirm whether the IDE is available in production', 'Check whether authentication is enforced before query execution']
    });
  }
  if (sampleQuerySucceeded && !introspectionEnabled) {
    findings.push({
      ruleId: 'unauthenticated-graphql-query',
      title: 'Benign unauthenticated GraphQL query succeeded',
      severity: 'medium',
      priorityScore: 45,
      priorityReasons: ['sample query returned data without authentication'],
      evidence: { endpoint, sampleQueryStatus: input.sampleQueryStatus },
      nextSteps: ['Verify intended public API scope', 'Test only non-destructive read queries authorized by the program']
    });
  }
  if (!introspectionEnabled && !sampleQuerySucceeded && hasAuthError) {
    findings.push({
      ruleId: 'graphql-auth-enforced',
      title: 'GraphQL endpoint appears to enforce authentication',
      severity: 'info',
      priorityScore: 5,
      priorityReasons: ['introspection or sample query returned authentication-related errors'],
      evidence: { endpoint, introspectionStatus: input.introspectionStatus, sampleQueryStatus: input.sampleQueryStatus },
      nextSteps: ['Use authorized credentials only if the program scope permits authenticated testing']
    });
  }
  const severityRank = { critical: 5, high: 4, medium: 3, low: 2, info: 1 };
  findings.sort((a, b) => b.priorityScore - a.priorityScore || String(a.ruleId).localeCompare(String(b.ruleId)));
  const highestSeverity = findings.reduce((current, finding) => severityRank[finding.severity] > severityRank[current || 'info'] ? finding.severity : current, findings.length ? 'info' : null);
  return {
    report: {
      summary: {
        endpoint,
        introspectionEnabled: Boolean(introspectionEnabled),
        unauthenticatedQuerySucceeded: Boolean(sampleQuerySucceeded),
        graphqlIdeExposed: Boolean(graphqlIdeExposed),
        authErrorObserved: Boolean(hasAuthError),
        riskyMutations: riskyMutations.length,
        sensitiveSchemaSignals: sensitiveSchemaSignals.length,
        findings: findings.filter((finding) => finding.severity !== 'info').length,
        highestSeverity,
        topFinding: findings[0]?.title || null
      },
      authorizationNotes: typeof input.authorizationNotes === 'string' && input.authorizationNotes.trim().length > 0 ? input.authorizationNotes.trim() : null,
      dataSources: {
        endpointLanding: { status: input.landingStatus, ok: statusOk(input.landingStatus) },
        introspection: { status: input.introspectionStatus, statusText: input.introspectionStatusText || null, ok: statusOk(input.introspectionStatus) },
        sampleQuery: { status: input.sampleQueryStatus, ok: statusOk(input.sampleQueryStatus) }
      },
      findings,
      schemaPreview: introspectionEnabled ? {
        queryType: schema?.queryType?.name || null,
        mutationType: schema?.mutationType?.name || null,
        subscriptionType: schema?.subscriptionType?.name || null,
        typeNames: types.map((type) => type?.name).filter(Boolean).slice(0, 80)
      } : null,
      nextSteps: ['Manually verify findings in a browser or GraphQL client inside the authorized scope', 'Prioritize introspection plus risky mutations over IDE exposure alone', 'Do not execute destructive mutations during triage']
    }
  };
}
